for (start,end), q in zip(spans, quotes):
    entry = {
        "span_start": start,
        "span_end": end,
        "span_text": q,
        "citation_type": "Aya" if quotes.index(q) < 2 else "Hadeeth",
        "is_valid": False,
        "aya_reference": {},
        "hadeeth_reference": {},
        "corrected_text": "خطأ",
        "completely_invalid": True
    }
    # fill references accordingly
    if entry["citation_type"]=="Aya":
        if quotes.index(q)==0:
            entry["aya_reference"] = {"sura_name":"الشعراء","sura_number":26,"aya_number":88}
        else:
            entry["aya_reference"] = {"sura_name":"المائدة","sura_number":5,"aya_number":109}
    else:
        entry["hadeeth_reference"] = {"collection_name":"Sahih Bukhari" if quotes.index(q)==2 else "Sahih Muslim",
                                      "book_number":0,"hadith_number":0}
    citations.append(entry)
